"""Ride selection strategies — the extensibility seam (Strategy pattern).

The service filters rides by route+seats (a hard constraint); a strategy only
RANKS the survivors and returns the best one. Adding a new preference = one new
class here, zero changes to the service.
"""
from __future__ import annotations

from abc import ABC, abstractmethod

from models import Ride


# ── WHY THIS CLASS ────────────────────────────────────────────────────────────
# The seam. One method: given already-filtered candidates, pick the best, or
# return None if this preference cannot be satisfied (e.g. preferred vehicle absent).
# 🎙️ "This is the Strategy interface. The service hands it valid candidates and
#     asks 'which one?'. The service never knows the concrete preference."
class RideSelectionStrategy(ABC):
    @abstractmethod
    def select(self, candidates: list[Ride]) -> Ride | None:
        ...


class EarliestEndingStrategy(RideSelectionStrategy):
    """Earliest-ending / lowest-duration-finish ride."""
    def select(self, candidates: list[Ride]) -> Ride | None:
        # WHY: tie-break on id so the result is deterministic (testable).
        return min(candidates, key=lambda r: (r.end_time, r.id), default=None)


class LowestDurationStrategy(RideSelectionStrategy):
    """Shortest trip duration."""
    def select(self, candidates: list[Ride]) -> Ride | None:
        return min(candidates, key=lambda r: (r.duration_hours, r.id), default=None)


class MostVacantStrategy(RideSelectionStrategy):
    """Most empty seats — roomiest ride."""
    def select(self, candidates: list[Ride]) -> Ride | None:
        # WHY: max available_seats; -id keeps the tie-break deterministic.
        return max(candidates, key=lambda r: (r.available_seats, r.id), default=None)


class PreferredVehicleStrategy(RideSelectionStrategy):
    """Only rides with the requested vehicle model; among those, most vacant."""
    def __init__(self, model: str) -> None:
        self._model = model.lower()

    def select(self, candidates: list[Ride]) -> Ride | None:
        # WHY: this is a SECOND filter, not just a ranking — if no ride has the
        #      preferred vehicle we return None and the service raises a clear
        #      NoRideAvailable. We do NOT silently substitute another vehicle.
        # ✗ SKIPPED: auto-falling back to earliest-ending — that hides intent.
        #            A "fallback chain" would be a new composite strategy (extension point).
        matching = [r for r in candidates if r.vehicle.model.lower() == self._model]
        return max(matching, key=lambda r: (r.available_seats, r.id), default=None)
